Below is a **single, self‑contained** source file that you can drop into the BlockSci source tree (or compile together with it).  
It contains

* a **public C header** (`blocksci.h`) that any C program can include, and  
* a **C++ wrapper implementation** that bridges the BlockSci C++ iterator to the C callback.

The design mirrors what pandas/Polars do for “apply‑per‑row”: the C user supplies a plain C function pointer (with an optional `void *user_data` cookie) that is called for **every block**.  
The wrapper does **no allocation per‑block**, copies only the few fields that are needed for the callback, and aborts the walk as soon as the callback returns a non‑zero error code – this keeps the hot path as tight as possible.

```c
/*********************************************************************
 *  blocksci.h  –  C bindings for BlockSci block iteration
 *
 *  This file is deliberately self‑contained: it contains the public
 *  C API (the header) *and* the C++ implementation that forwards the
 *  iteration to a C callback.  The file can be compiled with a C++
 *  compiler (e.g. g++/clang++) and linked into a shared library that
 *  C programs link against.
 *
 *  --------------------------------------------------------------
 *  How to use from C:
 *
 *      #include "blocksci.h"
 *
 *      // The data you want to see for each block.
 *      typedef struct {
 *          uint64_t height;        // block height (0‑based)
 *          uint64_t timestamp;     // Unix epoch seconds
 *          uint64_t tx_count;      // number of transactions in the block
 *          uint64_t size;          // block size in bytes
 *      } bsci_block_t;
 *
 *      // Your per‑block function.  Return 0 to continue, non‑zero to stop.
 *      int my_per_block(const bsci_block_t *blk, void *user);
 *
 *      int main(void) {
 *          bsci_chain_t *chain = NULL;
 *          int rc = bsci_chain_open("/path/to/blocksci/data", &chain);
 *          if (rc != 0) return rc;
 *
 *          // Walk the chain, passing a pointer that will be received as `user`.
 *          rc = bsci_chain_foreach_block(chain, my_per_block, NULL);
 *
 *          bsci_chain_close(chain);
 *          return rc;
 *      }
 *
 *  --------------------------------------------------------------
 *  Build (example):
 *
 *      g++ -std=c++20 -fPIC -shared -O3 -Wall -Wextra \
 *          -I/path/to/blocksci/include \
 *          -o libblocksci_c.so blocksci.h \
 *          -lblocksci   # (link to the original C++ library)
 *
 *  Then from C:
 *
 *      gcc -I. my_program.c -L. -lblocksci_c -lblocksci -o my_program
 *
 *********************************************************************/

#ifndef BLOCKSCI_H
#define BLOCKSCI_H

/* ------------------------------------------------------------------ *
 *  Public C API
 * ------------------------------------------------------------------ */

#ifdef __cplusplus
extern "C" {
#endif

/* Opaque handle representing an opened BlockSci chain. */
typedef struct bsci_chain_s bsci_chain_t;

/* Structure passed to the user‑provided callback for each block.
 * Only a handful of fields are exposed; if you need more, extend the
 * struct (and the wrapper below) – the layout is part of the ABI.
 */
typedef struct {
    uint64_t height;        /* Block height (0‑based) */
    uint64_t timestamp;     /* Unix epoch seconds */
    uint64_t tx_count;      /* Number of transactions in the block */
    uint64_t size;          /* Block size in bytes */
} bsci_block_t;

/* Callback prototype.
 *   blk   – pointer to a read‑only bsci_block_t describing the current block.
 *   user  – opaque pointer supplied by the caller (may be NULL).
 *
 * Return 0 to keep iterating, any non‑zero value aborts the walk and is
 * propagated back to the caller of `bsci_chain_foreach_block`.
 */
typedef int (*bsci_block_cb_t)(const bsci_block_t *blk, void *user);

/* Open a BlockSci data directory.
 *   path      – filesystem path to the BlockSci dataset (generated by
 *               `blocksci`'s `make` step).
 *   out_chain – receives a handle that must later be closed with
 *               `bsci_chain_close`.
 *
 * Returns 0 on success, non‑zero on error (e.g. path does not exist,
 * missing files, etc.).  The exact error codes are implementation‑defined
 * but 1 is “generic failure”.
 */
int bsci_chain_open(const char *path, bsci_chain_t **out_chain);

/* Close a previously opened chain and free all resources. */
void bsci_chain_close(bsci_chain_t *chain);

/* Walk the whole blockchain, invoking `cb` for each block.
 *
 *   chain   – a handle obtained from `bsci_chain_open`.
 *   cb      – user‑supplied per‑block callback (must not be NULL).
 *   user    – opaque pointer that will be passed unchanged to `cb`.
 *
 * Returns 0 if the iteration completed normally, or the non‑zero value
 * returned by `cb` if the callback asked to abort early.  Errors opening
 * the iterator also return non‑zero (currently 2).
 */
int bsci_chain_foreach_block(bsci_chain_t *chain,
                             bsci_block_cb_t cb,
                             void *user);

#ifdef __cplusplus
} /* extern "C" */
#endif

/* ------------------------------------------------------------------ *
 *  Inline helper macro for C++ users (optional)
 * ------------------------------------------------------------------ */

#ifdef __cplusplus
/* C++ friendly wrapper that accepts any callable (lambda, functor, …)
 * and forwards it to the C API.  This is useful when you compile a C++
 * program against the same header.
 */
template <typename Callable>
inline int bsci_chain_foreach_block_cpp(bsci_chain_t *chain,
                                        Callable &&fn)
{
    struct Context {
        Callable *callable;
        static int trampoline(const bsci_block_t *blk, void *user) {
            Context *ctx = static_cast<Context*>(user);
            return (*ctx->callable)(*blk);
        }
    } ctx{ &fn };
    return bsci_chain_foreach_block(chain, Context::trampoline, &ctx);
}
#endif

/* ------------------------------------------------------------------ *
 *  Implementation (C++) – compiled only once per translation unit.
 * ------------------------------------------------------------------ */

#ifdef __cplusplus   /* ------------------------------------------------- */

#include <cstddef>
#include <cstdint>
#include <cstdio>
#include <cstring>
#include <memory>
#include <vector>
#include <stdexcept>

/* ---- BlockSci includes ------------------------------------------------
 * You must have the BlockSci headers available in your include path.
 * Adjust the include path if your installation is in a non‑standard
 * location.
 * -------------------------------------------------------------------- */
#include <blocksci/chain/chain.hpp>
#include <blocksci/cluster/cluster.hpp>
#include <blocksci/heuristics.hpp>
#include <blocksci/address.hpp>
#include <blocksci/tx.hpp>
#include <blocksci/block.hpp>

using namespace blocksci;

/* ---- Opaque handle definition ---------------------------------------- */
struct bsci_chain_s {
    /* The real BlockSci chain object.  We keep it inside a std::unique_ptr
     * so that the C API can manage lifetime with a simple `delete`.
     */
    std::unique_ptr<Chain> chain;
};

/* ---- Helper: translate a BlockSci block into the C struct ------------- */
static inline void fill_c_block(const blocksci::Block &src, bsci_block_t *dst)
{
    dst->height    = src.height();
    dst->timestamp = src.timestamp();
    dst->tx_count  = src.txes.size();
    dst->size      = src.size;
}

/* ---- Public API implementation ---------------------------------------- */
extern "C" {

/* Open a BlockSci dataset ------------------------------------------------ */
int bsci_chain_open(const char *path, bsci_chain_t **out_chain)
{
    if (!path || !out_chain) return 1;               // invalid args

    try {
        auto chain_ptr = std::make_unique<Chain>(std::string(path));
        // The Chain constructor will throw on failure (missing files, etc.)
        *out_chain = new bsci_chain_s{ std::move(chain_ptr) };
        return 0;                                    // success
    } catch (const std::exception &e) {
        // In a real library you might want to expose the message via a
        // separate `bsci_last_error()` function.  For brevity we just
        // return a generic error code.
        std::fprintf(stderr, "BlockSci open error: %s\n", e.what());
        return 1;
    }
}

/* Close ----------------------------------------------------------------- */
void bsci_chain_close(bsci_chain_t *chain)
{
    delete chain;   // unique_ptr will destroy the Chain automatically
}

/* Iterate --------------------------------------------------------------- */
int bsci_chain_foreach_block(bsci_chain_t *chain,
                             bsci_block_cb_t cb,
                             void *user)
{
    if (!chain || !cb) return 1;                     // bad arguments

    const Chain &c = *chain->chain;                 // reference to the real chain

    // The iterator is cheap – it yields a const Block& by reference.
    // We allocate the C struct once and reuse it for each callback,
    // thus avoiding per‑iteration heap traffic.
    bsci_block_t cblk;

    try {
        for (const Block &blk : c) {
            fill_c_block(blk, &cblk);
            int rc = cb(&cblk, user);
            if (rc != 0) return rc;                // early abort requested by user
        }
        return 0;                                  // normal completion
    } catch (const std::exception &e) {
        std::fprintf(stderr, "BlockSci iteration error: %s\n", e.what());
        return 2;                                  // iterator failure
    }
}

}   // extern "C"

#endif   // __cplusplus
#endif   // BLOCKSCI_H
```

